class Bird:
  def fly(self):
    return 'Flapping wings'

class Penguin(Bird):
  def fly(self):
    raise NotImplementedError('Cannot fly')

def make_bird_fly(bird):
  print(bird.fly())

penguin = Penguin()
make_bird_fly(penguin)  # Crashes!

challenge.solution:
class DataExporter:
  def export(self, data):
    pass

class JSONExporter(DataExporter):
  def export(self, data):
    print(f'JSON: {data}')

class CSVExporter(DataExporter):
  def export(self, data):
    keys = ','.join(data.keys())
    vals = ','.join(str(v) for v in data.values())
    print(f'CSV: {keys}\n{vals}')

def process_export(exporter, data):
  exporter.export(data)

